class LogoManager{constructor(){this.controllerUrl="index.php?controller=Logo",this.modalEl=document.getElementById("modalEditLogo"),this.modal=this.modalEl?new bootstrap.Modal(this.modalEl):null,this.init()}init(){this.bindEvents()}bindEvents(){let t=null;const e=document.getElementById("modalDeleteLogo"),o=e?new bootstrap.Modal(e):null;document.body.addEventListener("click",(e=>{const a=e.target.closest(".btn-edit-seo");a&&(e.preventDefault(),this.openEditModal(a.dataset.id));const s=e.target.closest(".btn-activate-logo");s&&(e.preventDefault(),this.activateLogo(s.dataset.id));const n=e.target.closest(".btn-delete-logo");n&&(e.preventDefault(),t=n.dataset.id,o&&o.show())}));const a=document.getElementById("btnConfirmDeleteLogo");if(a&&a.addEventListener("click",(()=>{t&&(this.deleteLogo(t),o&&o.hide(),t=null)})),this.modalEl){const t=this.modalEl.querySelector("form");t&&t.addEventListener("submit",(()=>{setTimeout((()=>{this.refreshGallery()}),1200)}))}}async openEditModal(t){if(this.modal){document.getElementById("edit_id_logo").value=t;try{const e=await fetch(`${this.controllerUrl}&action=getContent&id=${t}`,{headers:{"X-Requested-With":"XMLHttpRequest"}}),o=await e.json();if(o.status&&o.data){for(const[t,e]of Object.entries(o.data)){const o=document.getElementById(`edit_alt_${t}`),a=document.getElementById(`edit_title_${t}`);o&&(o.value=e.alt_logo||""),a&&(a.value=e.title_logo||"")}const t=this.modalEl.querySelector(".dropdown-lang .dropdown-item");t&&t.click(),this.modal.show()}}catch(t){console.error("Erreur récupération contenu logo:",t),"undefined"!=typeof MagixToast&&MagixToast.error("Impossible de charger les données.")}}}async activateLogo(t){try{const e=new URLSearchParams;e.append("id",t);const o=await fetch(`${this.controllerUrl}&action=activate`,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded","X-Requested-With":"XMLHttpRequest"},body:e.toString()}),a=await o.json();a.status?("undefined"!=typeof MagixToast&&MagixToast.success(a.message),this.refreshGallery()):"undefined"!=typeof MagixToast&&MagixToast.error(a.message)}catch(t){console.error("Erreur activation:",t)}}async deleteLogo(t){try{const e=new URLSearchParams;e.append("id",t);const o=await fetch(`${this.controllerUrl}&action=delete`,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded","X-Requested-With":"XMLHttpRequest"},body:e.toString()}),a=await o.json();a.status&&("undefined"!=typeof MagixToast&&MagixToast.success(a.message),this.refreshGallery())}catch(t){console.error("Erreur suppression:",t)}}async refreshGallery(){try{const t=await fetch(`${this.controllerUrl}&action=getImages`,{headers:{"X-Requested-With":"XMLHttpRequest"}}),e=await t.json(),o=document.getElementById("block-img");o&&e.result&&(o.innerHTML=e.result)}catch(t){console.error("Erreur rafraîchissement galerie:",t)}}}